CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_lon_m_loan_card() RETURNS trigger AS $BODY$
DECLARE li_ck integer;
BEGIN
--return ;
  /* เอาออกเพราะจะทำให้เกิด Mutating
  if :new.loan_contract_no is null or :new.loan_contract_no = ' ' then
    spa_dberrcol('sc_lon_m_loan_card','loan_contract_no',:new.loan_contract_no);
  else
    if :old.loan_contract_no is null or :old.loan_contract_no <> :new.loan_contract_no  then
      if pka_com_valid.loan_contract_no(:new.loan_contract_no)= '1' then
        spa_dberrcol('sc_lon_m_loan_card','loan_contract_no',:new.loan_contract_no||',มีอยู่แล้ว');
      end if;
    end if;
  end if; */
  if coalesce(NEW.fixed_payment::text, '') = '' then NEW.fixed_payment := 0;end if;
  if coalesce(NEW.bonus_amount::text, '') = '' then NEW.bonus_amount := 0;end if;
  if coalesce(NEW.principal_balance::text, '') = '' then NEW.principal_balance := 0;end if;
  if coalesce(NEW.interest_arrear::text, '') = ''  then NEW.interest_arrear := 0;end if;
  if coalesce(NEW.old_interest_arrear::text, '') = '' then NEW.old_interest_arrear := 0;end if;
  if coalesce(NEW.interest_arrear_year::text, '') = '' then NEW.interest_arrear_year :=0;end if;
  if coalesce(NEW.last_period::text, '') = '' then NEW.last_period :=0;end if;
  if coalesce(NEW.pending_amount::text, '') = '' then NEW.pending_amount := 0;end if;
  if coalesce(NEW.pending_interest::text, '') = '' then NEW.pending_interest := 0;end if;
  if coalesce(NEW.year_total_interest::text, '') = '' then NEW.year_total_interest :=0;end if;
  if coalesce(NEW.entry_id::text, '') = '' then NEW.entry_id := current_setting('app.login_id', true);end if;
  if coalesce(NEW.entry_date::text, '') = '' then NEW.entry_date := statement_timestamp();end if;
  if coalesce(NEW.branch_id::text, '') = '' then NEW.branch_id := current_setting('app.login_br', true);end if;
  if coalesce(NEW.backlist_count::text, '') = ''  then NEW.backlist_count := 0;end if;
  if coalesce(NEW.fixed_interest_rate::text, '') = '' then NEW.fixed_interest_rate := 0;end if;
  if coalesce(NEW.BEGIN_balance::text, '') = '' then NEW.BEGIN_balance := 0;end if;
  if coalesce(NEW.principal_arr_all::text, '') = '' then  NEW.principal_arr_all := 0;end if;
  if coalesce(NEW.period_compomise::text, '') = '' then NEW.period_compomise := 0;end if;
  if coalesce(NEW.pending_month_arr::text, '') = '' then NEW.pending_month_arr := 0;end if;
  if coalesce(NEW.loan_code::text, '') = '' or NEW.loan_code = ' ' or NEW.loan_code = '  ' then NEW.loan_code := '0';end if;

  if coalesce(NEW.keeping_status::text, '') = '' or NEW.keeping_status != '1' then
    NEW.keeping_status := '0';
  end if;

  if coalesce(NEW.drop_payment_status::text, '') = '' or NEW.drop_payment_status = ' ' then
    NEW.drop_payment_status := '0';
  end if;

  if coalesce(NEW.contact_status::text, '') = '' or NEW.contact_status != '1' then
    NEW.contact_status := '0';
  end if;

  if coalesce(NEW.close_status::text, '') = '' or NEW.close_status != '1' then
    NEW.close_status := '0';
  end if;

  -- เวลาที่แก้ไขล่าสุด(บังคับ)
  NEW.last_access_time := to_char(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');

if coalesce(NEW.transfer_status::text, '') = '' then NEW.transfer_status := '0';end if;
if coalesce(NEW.transfer_amount::text, '') = '' then NEW.transfer_amount := 0;end if;

  --Faifa กองทุนรับภาระ loan_code = C
  if NEW.membership_no = 'fundmem' then
    NEW.loan_code := 'C';
  end if;
  --Niorn 2020-08-01 KTM ผ่านรายการ สัญญาที่เก็บแต่ดอกเบี้ยค้าง มันจะไม่มี calint_to ทำให้ last_calcint_date เป็น null
  if coalesce(NEW.last_calcint_date::text, '') = '' then NEW.last_calcint_date := NEW.last_process_date;end if;

--    --KTM ลูกหนี้รับภาระ คือ ลูกหนี้ขาดจากการเป็นสมาชิก loan_code = 1
--  if :new.loan_type = '3' and :new.loan_code = '0' then
--    :new.loan_code := '1';
--  end if;
  --Niorn krabi 2021-01-19 สัญญาทุกสัญญา default เก็บกับคนค้ำได้
  if coalesce(NEW.keep_with_coll::text, '') = '' then NEW.keep_with_coll := '1';end if;
  --Niorn 2022-12-31 Amnat เป็น null เฉลี่ยคืนผิด 
  if coalesce(NEW.drop_aver::text, '') = '' then NEW.drop_aver := '0';end if;


  --Niorn 2023-04-15 TGE เงินกู้ สอ อื่น หุ้นกู้ loan_code = 9
  if pka.isCoop('TGE') = '1' and NEW.membership_no like  '9%' then
    NEW.loan_code := '9';
  end if;

  --Niorn 2023-04-15 TGE ยกเลิกประมวลผล เซตสถานะ และตอน ตั้งตัวแทนไม่ให้ตั้ง
  --วันที่ยกเลิกประมวลผล ก่อน last_process  ถึงเข้าเคส  วันที่ผ่านรายการ sysdate จะมากกว่า last_process_date เสมอ ( ถ้าผ่านตรงวัน )
  if statement_timestamp()  < NEW.last_process_date 
     and OLD.keeping_status = '1' 
     and NEW.keeping_status = '0' then

    update sc_kep_t_monthly_receive_det
    set cancle_proc = '1' ,
    cancle_proc_id = current_setting('app.login_id', true) ,
    cancle_proc_date = statement_timestamp() 
    where receive_description = NEW.loan_contract_no
    and posting_status = '0'
    and int_to = NEW.last_process_date
;
--   --Niorn 2023-07-18 TGE ถ้าวันที่ประมวล = วันทึ่คิดดอก คือการผ่านรายการ ไม่ต้องยุ่งกับใบเสร็จ
--   if   :new.last_process_date != :new.last_calcint_date  then
--        --Niorn 2023-05-01 TGE ยกเลิกประมวลผล ต้องยกเลิกตัวแทน
--        select count( 1 ) into li_ck
--        from sc_kep_t_monthly_receive
--        where membership_no = :new.membership_no
--        and posted_run = '0'
--        and agent_active = '1'  
--        ;           
--        --if sql%rowcount <> 1 then
--        if li_ck > 0 then
--            spa_dberror('T98: กรุณายกเลิกตั้งลูกหนี้ตัวแทนก่อน ยกเลิกการประมวลผล');
--        end if;
--    end if ;
  end if;

--Niorn 2024-04-13 POT 
if coalesce(NEW.bonus_keeping_type::text, '') = '' then NEW.bonus_keeping_type := '0';end if;
if coalesce(NEW.bonus_keeping::text, '') = '' then NEW.bonus_keeping := 0;end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
